216	    /// CSS transition duration.
217	    pub transition_duration: Option<Duration>,
218	    /// Swipe distance threshold in pixels.
219	    pub swipe_threshold: Option<f64>,
220	    /// Whether the carousel is right-to-left.
221	    pub is_rtl: bool,
222	}
223	
224	impl Default for Props {
225	    fn default() -> Self {
226	        Self {
227	            id: String::new(),
228	            slide_count: NonZero::new(1).expect("non-zero"),
229	            index: None,
230	            default_index: None,
231	            loop_nav: false,
232	            auto_play: None,
233	            spacing: None,
234	            slides_per_view: None,
235	            slides_per_move: None,
236	            align: None,
237	            orientation: None,
238	            transition_duration: None,
239	            swipe_threshold: None,
240	            is_rtl: false,
241	        }
242	    }
243	}
244	```
245	
246	### 1.5 Full Machine Implementation
247	
248	```rust
249	pub struct Machine;
250	
251	impl ars_core::Machine for Machine {
252	    type State = State;
253	    type Event = Event;
254	    type Context = Context;
255	    type Props = Props;
256	    type Messages = Messages;
257	    type Api<'a> = Api<'a>;
258	
259	    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (Self::State, Self::Context) {
260	        let initial_state = if props.auto_play.is_some() {
261	            State::AutoPlaying
262	        } else {
263	            State::Idle
264	        };
265	        let initial_index = props.default_index.unwrap_or(0);
266	        let locale = env.locale.clone();
267	        let messages = messages.clone();
268	        let ctx = Context {
269	            index: props.index.clone()
270	                .unwrap_or_else(|| Bindable::uncontrolled(initial_index)),
271	            slide_count: props.slide_count,
272	            loop_nav: props.loop_nav,
273	            auto_play: props.auto_play.clone(),
274	            auto_play_stopped: false,
275	            auto_play_paused: false,
276	            spacing: props.spacing.unwrap_or(0.0),
277	            slides_per_view: props.slides_per_view.unwrap_or(1.0),
278	            slides_per_move: props.slides_per_move.unwrap_or(1),
279	            align: props.align.unwrap_or_default(),
280	            orientation: props.orientation.unwrap_or_default(),
281	            is_rtl: props.is_rtl,
282	            transition_duration: props.transition_duration
283	                .unwrap_or_else(|| Duration::from_millis(300)),
284	            drag_start_pos: None,
285	            drag_delta: 0.0,
286	            swipe_threshold: props.swipe_threshold.unwrap_or(50.0),
287	            swipe_velocity: 0.0,
288	            drag_last_timestamp: None,
289	            locale,
290	            messages,
291	            ids: ComponentIds::from_id(&props.id),
292	        };
293	        (initial_state, ctx)
294	    }
295	
296	    fn transition(
297	        state: &Self::State,
298	        event: &Self::Event,
299	        ctx: &Self::Context,
300	        props: &Self::Props,
301	    ) -> Option<TransitionPlan<Self>> {
302	        match event {
303	            Event::GoToSlide { index } => {
304	                if *state == State::Transitioning { return None; }
305	                let idx = *index;
306	                Some(TransitionPlan::to(State::Transitioning).apply(move |ctx| {
307	                    ctx.index.set(idx);
308	                }))
309	            }
310	
311	            Event::GoToNext => {
312	                if *state == State::Transitioning || !ctx.can_go_next() { return None; }
313	                let step = ctx.slides_per_move as isize;
314	                let next = ctx.clamp_index(ctx.current_index() as isize + step);
315	                let stop = ctx.auto_play.as_ref().map_or(false, |o| o.stop_on_interaction);
316	                Some(TransitionPlan::to(State::Transitioning).apply(move |ctx| {
317	                    ctx.index.set(next);
318	                    if stop { ctx.auto_play_stopped = true; }
319	                }))
320	            }
321	
322	            Event::GoToPrev => {
323	                if *state == State::Transitioning || !ctx.can_go_prev() { return None; }
324	                let step = ctx.slides_per_move as isize;
325	                let prev = ctx.clamp_index(ctx.current_index() as isize - step);
326	                let stop = ctx.auto_play.as_ref().map_or(false, |o| o.stop_on_interaction);
327	                Some(TransitionPlan::to(State::Transitioning).apply(move |ctx| {
328	                    ctx.index.set(prev);
329	                    if stop { ctx.auto_play_stopped = true; }
330	                }))
331	            }
332	
333	            Event::TransitionEnd => {
334	                if ctx.auto_play.is_some() && !ctx.auto_play_stopped && !ctx.auto_play_paused {
335	                    Some(TransitionPlan::to(State::AutoPlaying))
336	                } else {
337	                    Some(TransitionPlan::to(State::Idle))
338	                }
339	            }
340	
341	            Event::AutoPlayStart => {
342	                if ctx.auto_play_stopped || ctx.auto_play.is_none() { return None; }
343	                let interval = ctx.auto_play.as_ref()?.interval;
344	                Some(TransitionPlan::to(State::AutoPlaying).with_named_effect(
345	                    "auto-play",
346	                    move |_ctx, _props, send| {
347	                        let handle = set_interval(move || send(Event::AutoPlayTick), interval);
348	                        Box::new(move || clear_interval(handle))
349	                    },
350	                ))
351	            }
352	
353	            Event::AutoPlayStop => {
354	                Some(TransitionPlan::to(State::Idle).apply(|ctx| {
355	                    ctx.auto_play_stopped = true;
356	                }).cancel_effect("auto-play"))
357	            }
358	
359	            Event::AutoPlayTick => {
360	                if *state != State::AutoPlaying { return None; }
361	                let step = ctx.slides_per_move as isize;
362	                let next = ctx.clamp_index(ctx.current_index() as isize + step);
363	                Some(TransitionPlan::to(State::Transitioning).apply(move |ctx| {
364	                    ctx.index.set(next);
365	                }))
366	            }
367	
368	            Event::AutoPlayPause => {
369	                let plan = if *state == State::AutoPlaying {
370	                    TransitionPlan::to(State::Idle)
371	                } else {
372	                    TransitionPlan::new()
373	                };
374	                Some(plan.apply(|ctx| { ctx.auto_play_paused = true; }).cancel_effect("auto-play"))
375	            }
376	
377	            Event::AutoPlayResume => {
378	                if ctx.auto_play_stopped { return None; }
379	                if let Some(ref opts) = ctx.auto_play {
380	                    let interval = opts.interval;
381	                    return Some(TransitionPlan::to(State::AutoPlaying).apply(|ctx| {
382	                        ctx.auto_play_paused = false;
383	                    }).with_named_effect("auto-play", move |_ctx, _props, send| {
384	                        let handle = set_interval(move || send(Event::AutoPlayTick), interval);
385	                        Box::new(move || clear_interval(handle))
386	                    }));
387	                }
388	                Some(TransitionPlan::context_only(|ctx| { ctx.auto_play_paused = false; }))
389	            }
390	
391	            Event::PointerDown { pos, timestamp } => {
392	                let p = *pos;
393	                let ts = *timestamp;
394	                Some(TransitionPlan::context_only(move |ctx| {
395	                    ctx.drag_start_pos = Some(p);
396	                    ctx.drag_delta = 0.0;
397	                    ctx.swipe_velocity = 0.0;
398	                    ctx.drag_last_timestamp = Some(ts);
399	                }).cancel_effect("auto-play"))
400	            }
401	
402	            Event::PointerMove { pos, timestamp } => {
403	                if ctx.drag_start_pos.is_none() { return None; }
404	                let p = *pos;
405	                let ts = *timestamp;
406	                let start = ctx.drag_start_pos?;
407	                let prev_delta = ctx.drag_delta;
408	                let prev_ts = ctx.drag_last_timestamp;
409	                Some(TransitionPlan::context_only(move |ctx| {
410	                    ctx.drag_delta = p - start;
411	                    let pixel_delta = ctx.drag_delta - prev_delta;
412	                    let dt = prev_ts.map_or(0.0, |t| ts - t);
413	                    ctx.swipe_velocity = if dt > 0.0 { pixel_delta / dt } else { 0.0 };
414	                    ctx.drag_last_timestamp = Some(ts);
415	                }))
416	            }
417	
418	            Event::PointerUp => {
419	                let delta = ctx.drag_delta;
420	                let velocity = ctx.swipe_velocity;
421	                let threshold = ctx.swipe_threshold;
422	                // A brisk flick (>0.5 px/ms) reduces the distance threshold.
423	                let effective = if velocity.abs() > 0.5 { threshold * 0.3 } else { threshold };
424	
425	                let cur = ctx.current_index() as isize;
426	                let next_idx = if delta < -effective && ctx.can_go_next() {
427	                    Some(ctx.clamp_index(cur + 1))
428	                } else if delta > effective && ctx.can_go_prev() {
429	                    Some(ctx.clamp_index(cur - 1))
430	                } else {
431	                    None
432	                };
433	
434	                Some(TransitionPlan::to(State::Idle).apply(move |ctx| {
435	                    ctx.drag_start_pos = None;
436	                    ctx.drag_delta = 0.0;
437	                    ctx.swipe_velocity = 0.0;
438	                    ctx.drag_last_timestamp = None;
439	                    if let Some(idx) = next_idx {
440	                        ctx.index.set(idx);
441	                    }
442	                }))
443	            }
444	
445	            Event::PointerCancel => {
446	                Some(TransitionPlan::context_only(|ctx| {
447	                    ctx.drag_start_pos = None;
448	                    ctx.drag_delta = 0.0;
449	                    ctx.swipe_velocity = 0.0;
450	                    ctx.drag_last_timestamp = None;
451	                }))
452	            }
453	
454	            Event::FocusSlide { index } => {
455	                let idx = *index;
456	                let current = ctx.current_index();
457	                let should_pause = ctx.auto_play.as_ref().map_or(false, |o| o.pause_on_focus);
458	                Some(TransitionPlan::context_only(move |ctx| {
459	                    if idx != current { ctx.index.set(idx); }
460	                    if should_pause { ctx.auto_play_paused = true; }
461	                }))
462	            }
463	
464	            Event::Blur => {
465	                if ctx.auto_play_paused && !ctx.auto_play_stopped {
466	                    if let Some(ref opts) = ctx.auto_play {
467	                        let interval = opts.interval;
468	                        return Some(TransitionPlan::to(State::AutoPlaying).apply(|ctx| {
469	                            ctx.auto_play_paused = false;
470	                        }).with_named_effect("auto-play", move |_ctx, _props, send| {
471	                            let handle = set_interval(move || send(Event::AutoPlayTick), interval);
472	                            Box::new(move || clear_interval(handle))
473	                        }));
474	                    }
475	                }
476	                None
477	            }
478	        }
479	    }
480	
481	    fn connect<'a>(
482	        state: &'a Self::State,
483	        ctx: &'a Self::Context,
484	        props: &'a Self::Props,
485	        send: &'a dyn Fn(Self::Event),
486	    ) -> Self::Api<'a> {
487	        Api { state, ctx, props, send }
488	    }
489	}
490	```
