653	        attrs.set(scope_attr, scope_val);
654	        attrs.set(part_attr, part_val);
655	        let is_playing = !self.ctx.auto_play_stopped && !self.ctx.auto_play_paused;
656	        attrs.set(HtmlAttr::Data("ars-state"), if is_playing { "playing" } else { "paused" });
