661	    /// Attrs for the progress text element (e.g., "2 of 5").
662	    pub fn progress_text_attrs(&self) -> AttrMap {
663	        let mut attrs = AttrMap::new();
664	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::ProgressText.data_attrs();
665	        attrs.set(scope_attr, scope_val);
666	        attrs.set(part_attr, part_val);
667	        attrs.set(HtmlAttr::Aria(AriaAttr::Live), "polite");
668	        attrs.set(HtmlAttr::Aria(AriaAttr::Atomic), "true");
669	        attrs
670	    }
671	
672	    /// Human-readable progress string (e.g., "Slide 2 of 5").
673	    pub fn progress_text(&self) -> String {
674	        (self.ctx.messages.slide_label)(
675	            self.ctx.current_index() + 1,
676	            self.ctx.slide_count.get(),
677	            &self.ctx.locale,
678	        )
679	    }
680	
681	    pub fn on_root_keydown(&self, data: &KeyboardEventData) {
682	        let is_horizontal = self.ctx.orientation == Orientation::Horizontal;
683	        let (prev_key, next_key) = if is_horizontal {
684	            if self.ctx.is_rtl {
685	                (KeyboardKey::ArrowRight, KeyboardKey::ArrowLeft)
686	            } else {
687	                (KeyboardKey::ArrowLeft, KeyboardKey::ArrowRight)
688	            }
689	        } else {
690	            (KeyboardKey::ArrowUp, KeyboardKey::ArrowDown)
691	        };
692	        match data.key {
693	            k if k == prev_key => (self.send)(Event::GoToPrev),
694	            k if k == next_key => (self.send)(Event::GoToNext),
695	            KeyboardKey::Home => (self.send)(Event::GoToSlide { index: 0 }),
696	            KeyboardKey::End => (self.send)(Event::GoToSlide {
697	                index: self.ctx.slide_count.get().saturating_sub(1),
698	            }),
699	            _ => {}
700	        }
701	    }
702	
703	    pub fn on_prev_trigger_click(&self) { (self.send)(Event::GoToPrev); }
704	    pub fn on_next_trigger_click(&self) { (self.send)(Event::GoToNext); }
705	    pub fn on_indicator_click(&self, index: usize) { (self.send)(Event::GoToSlide { index }); }
706	    pub fn on_auto_play_trigger_click(&self) {
707	        if self.ctx.auto_play_stopped || self.ctx.auto_play_paused {
708	            (self.send)(Event::AutoPlayResume);
709	        } else {
710	            (self.send)(Event::AutoPlayPause);
711	        }
712	    }
713	    pub fn on_viewport_pointerdown(&self, pos: f64, timestamp: f64) {
714	        (self.send)(Event::PointerDown { pos, timestamp });
715	    }
716	    pub fn on_viewport_pointermove(&self, pos: f64, timestamp: f64) {
717	        (self.send)(Event::PointerMove { pos, timestamp });
718	    }
719	    pub fn on_viewport_pointerup(&self) { (self.send)(Event::PointerUp); }
720	}
