727	            Part::Root => self.root_attrs(),
728	            Part::Viewport => self.viewport_attrs(),
729	            Part::ItemGroup => self.item_group_attrs(),
730	            Part::Item { index } => self.item_attrs(index),
731	            Part::PrevTrigger => self.prev_trigger_attrs(),
