590	    fn transition(
591	        state: &Self::State,
592	        event: &Self::Event,
593	        ctx: &Self::Context,
594	        _props: &Self::Props,
595	    ) -> Option<TransitionPlan<Self>> {
596	        match event {
597	            Event::GoToSlide { index } => {
598	                if *state == State::Transitioning {
599	                    return None;
600	                }
601	
602	                // A direct jump never wraps; clamp out-of-range targets to the
603	                // last slide so `current_index` can never exceed the slide
604	                // count (every connect method relies on that invariant).
605	                let idx = (*index).min(ctx.slide_count.get() - 1);
606	                Some(
607	                    TransitionPlan::to(State::Transitioning).apply(move |ctx: &mut Context| {
608	                        ctx.index.set(idx);
609	                    }),
610	                )
611	            }
612	
613	            Event::GoToNext => {
614	                if *state == State::Transitioning || !ctx.can_go_next() {
615	                    return None;
616	                }
617	
618	                let step = ctx.slides_per_move as isize;
619	
620	                let next = ctx.clamp_index(ctx.current_index() as isize + step);
621	
622	                let stop = ctx
623	                    .auto_play
624	                    .as_ref()
625	                    .is_some_and(|o| o.stop_on_interaction);
626	
627	                Some(
628	                    TransitionPlan::to(State::Transitioning).apply(move |ctx: &mut Context| {
629	                        ctx.index.set(next);
630	
631	                        if stop {
632	                            ctx.auto_play_stopped = true;
633	                        }
634	                    }),
635	                )
636	            }
637	
638	            Event::GoToPrev => {
639	                if *state == State::Transitioning || !ctx.can_go_prev() {
640	                    return None;
641	                }
642	
643	                let step = ctx.slides_per_move as isize;
644	
645	                let prev = ctx.clamp_index(ctx.current_index() as isize - step);
646	
647	                let stop = ctx
648	                    .auto_play
649	                    .as_ref()
650	                    .is_some_and(|o| o.stop_on_interaction);
651	
652	                Some(
653	                    TransitionPlan::to(State::Transitioning).apply(move |ctx: &mut Context| {
654	                        ctx.index.set(prev);
655	
656	                        if stop {
657	                            ctx.auto_play_stopped = true;
658	                        }
659	                    }),
660	                )
661	            }
662	
663	            Event::TransitionEnd => {
664	                if ctx.auto_play.is_some() && !ctx.auto_play_stopped && !ctx.auto_play_paused {
665	                    Some(TransitionPlan::to(State::AutoPlaying))
666	                } else {
667	                    Some(TransitionPlan::to(State::Idle))
668	                }
669	            }
670	
671	            Event::AutoPlayStart => {
672	                if ctx.auto_play_stopped || ctx.auto_play.is_none() {
673	                    return None;
674	                }
675	
676	                Some(
677	                    TransitionPlan::to(State::AutoPlaying)
678	                        .with_effect(PendingEffect::named(Effect::AutoPlayTimer)),
679	                )
680	            }
681	
682	            Event::AutoPlayStop => Some(
683	                TransitionPlan::to(State::Idle)
684	                    .apply(|ctx: &mut Context| {
685	                        ctx.auto_play_stopped = true;
686	                    })
687	                    .cancel_effect(Effect::AutoPlayTimer),
688	            ),
689	
690	            Event::AutoPlayTick => {
691	                if *state != State::AutoPlaying {
692	                    return None;
693	                }
694	
695	                let step = ctx.slides_per_move as isize;
696	
697	                let next = ctx.clamp_index(ctx.current_index() as isize + step);
698	
699	                Some(
700	                    TransitionPlan::to(State::Transitioning).apply(move |ctx: &mut Context| {
701	                        ctx.index.set(next);
702	                    }),
703	                )
704	            }
705	
706	            Event::AutoPlayPause => {
707	                let plan = if *state == State::AutoPlaying {
708	                    TransitionPlan::to(State::Idle)
709	                } else {
710	                    TransitionPlan::new()
711	                };
712	
713	                Some(
714	                    plan.apply(|ctx: &mut Context| {
715	                        ctx.auto_play_paused = true;
716	                    })
717	                    .cancel_effect(Effect::AutoPlayTimer),
718	                )
719	            }
720	
721	            Event::AutoPlayResume => {
722	                if ctx.auto_play_stopped {
723	                    return None;
724	                }
725	
726	                if ctx.auto_play.is_some() {
727	                    return Some(
728	                        TransitionPlan::to(State::AutoPlaying)
729	                            .apply(|ctx: &mut Context| {
730	                                ctx.auto_play_paused = false;
731	                            })
732	                            .with_effect(PendingEffect::named(Effect::AutoPlayTimer)),
733	                    );
734	                }
735	
736	                Some(TransitionPlan::context_only(|ctx: &mut Context| {
737	                    ctx.auto_play_paused = false;
738	                }))
739	            }
740	
741	            Event::PointerDown { pos, timestamp } => {
742	                let pos = *pos;
743	                let timestamp = *timestamp;
744	                Some(
745	                    TransitionPlan::context_only(move |ctx: &mut Context| {
746	                        ctx.drag_start_pos = Some(pos);
747	                        ctx.drag_delta = 0.0;
748	                        ctx.swipe_velocity = 0.0;
749	                        ctx.drag_last_timestamp = Some(timestamp);
750	                    })
751	                    .cancel_effect(Effect::AutoPlayTimer),
752	                )
753	            }
754	
755	            Event::PointerMove { pos, timestamp } => {
756	                let start = ctx.drag_start_pos?;
757	                let pos = *pos;
758	                let timestamp = *timestamp;
759	                let prev_delta = ctx.drag_delta;
760	                let prev_ts = ctx.drag_last_timestamp;
761	                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
762	                    ctx.drag_delta = pos - start;
763	
764	                    let pixel_delta = ctx.drag_delta - prev_delta;
765	                    let dt = prev_ts.map_or(0.0, |t| timestamp - t);
766	
767	                    ctx.swipe_velocity = if dt > 0.0 { pixel_delta / dt } else { 0.0 };
768	                    ctx.drag_last_timestamp = Some(timestamp);
769	                }))
770	            }
771	
772	            Event::PointerUp => {
773	                let delta = ctx.drag_delta;
774	                let velocity = ctx.swipe_velocity;
775	                let threshold = ctx.swipe_threshold;
776	
777	                // A brisk flick (>0.5 px/ms) reduces the distance threshold.
778	                let effective = if velocity.abs() > 0.5 {
779	                    threshold * 0.3
780	                } else {
781	                    threshold
782	                };
783	
784	                let cur = ctx.current_index() as isize;
