            let idx = (*index).min(ctx.slide_count.get() - 1);
            Some(TransitionPlan::to(State::Transitioning).apply(move |ctx| {
                ctx.index.set(idx);
            }))
        }

        Event::GoToNext => {
            if *state == State::Transitioning || !ctx.can_go_next() { return None; }
            let step = ctx.slides_per_move as isize;
