    fn slides_per_view_non_finite_is_normalized() {
        let ctx = service(Props {
            slides_per_view: Some(f64::NAN),
            ..props(3)
        })
        .context()
        .clone();
        assert_eq!(ctx.slides_per_view, 1.0);
    }

