fn on_props_changed(old: &Self::Props, new: &Self::Props) -> Vec<Self::Event> {
    assert_eq!(
        old.id, new.id,
        "carousel::Props.id must remain stable after initialization"
    );

    // Any prop change re-syncs the machine's mutable configuration,
    // controlled-index signal, and auto-play timer (see the `SyncProps`
    // arm). Mirrors the `splitter` convention.
    if old == new {
        Vec::new()
    } else {
        vec![Event::SyncProps { props: new.clone() }]
    }
}

