            pos: 100.0,
            timestamp: 0.0,
        }));
        drop(service.send(Event::PointerMove {
            pos: 40.0,
            timestamp: 1000.0,
        }));
        drop(service.send(Event::PointerUp));
        assert_eq!(service.context().current_index(), 2);
    }

